queries.sparql:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
SELECT ?sn ?an WHERE { ?l p:hasTraffic_Simulators ?s ; p:hasApplications ?a . ?s p:name ?sn . ?a p:name ?an . }

PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
PREFIX xsd: <http://www.w3.org/2001/XMLSchema#>
SELECT ?application_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasApplications ?child ; p:hasTraffic_Simulators ?parent . } GROUP BY ?child }
  ?child p:name ?application_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Traffic_Simulators } }
  FILTER(?nf = ?total)
}

ambiguous_dsl.choice_dsl:
PREFIX : <http://ambrosia.example.org/traffic#>
PREFIX p: <http://ambrosia.example.org/traffic/prop#>
CHOICE scope {
  distributive: { SELECT ?sn ?an WHERE { ?l p:hasTraffic_Simulators ?s ; p:hasApplications ?a . ?s p:name ?sn . ?a p:name ?an . } }
  collective: { SELECT ?application_name WHERE {
  { SELECT ?child (COUNT(DISTINCT ?parent) AS ?nf) WHERE { ?l p:hasApplications ?child ; p:hasTraffic_Simulators ?parent . } GROUP BY ?child }
  ?child p:name ?application_name .
  { SELECT (COUNT(DISTINCT ?t) AS ?total) WHERE { ?t a :Traffic_Simulators } }
  FILTER(?nf = ?total)
} }
}
